+                        generation_id: inventory.generation_id.clone(),
+                        shard_id: shard.shard_id.clone(),
+                        disposition: shard.disposition,
+                        reason: shard.reason.clone(),
+                        reclaimable_bytes: shard.reclaimable_bytes,
+                    })
+                })
+            })
+            .collect()
+    }
